"use strict";(self.webpackChunkmy_website=self.webpackChunkmy_website||[]).push([[85022],{1694:(e,t,n)=>{n.d(t,{A:()=>s});const s=n.p+"assets/images/us-housing-market-chart-1847c9b263fc9de2ec41f30d67e61641.webp"},17747:(e,t,n)=>{n.d(t,{A:()=>s});const s=n.p+"assets/images/us-housing-market-slowdown-20982abcdbc197a7096521f208e29d17.webp"},28453:(e,t,n)=>{n.d(t,{R:()=>o,x:()=>r});var s=n(96540);const a={},i=s.createContext(a);function o(e){const t=s.useContext(i);return s.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:o(e.components),s.createElement(i.Provider,{value:t},e.children)}},44168:e=>{e.exports=JSON.parse('{"permalink":"/blog/us-home-prices-decline-case-shiller-fhfa","editUrl":"https://github.com/khalid-naami/khalid-naami.github.io/tree/main/blog/2026-06-04-us-home-prices-fall-case-shiller-fhfa.md","source":"@site/blog/2026-06-04-us-home-prices-fall-case-shiller-fhfa.md","title":"Home Prices Fall: Case-Shiller & FHFA Slump","description":"U.S. home price growth slows as Case-Shiller and FHFA indexes fall. Pandemic-era booms in Texas and Florida reverse under energy shocks and a weak labor market.","date":"2026-06-04T14:00:00.000Z","tags":[{"inline":true,"label":"Global Economy","permalink":"/blog/tags/global-economy"},{"inline":true,"label":"Real Estate","permalink":"/blog/tags/real-estate"},{"inline":true,"label":"Debt","permalink":"/blog/tags/debt"},{"inline":true,"label":"Energy Markets","permalink":"/blog/tags/energy-markets"},{"inline":true,"label":"Central Banks","permalink":"/blog/tags/central-banks"},{"inline":true,"label":"Global Macro","permalink":"/blog/tags/global-macro"}],"readingTime":11.35,"hasTruncateMarker":true,"authors":[{"name":"Khalid Naami","title":"Founder, Owner, and CEO at Dashboard Options","description":"Professional academic writer, strategic analyst, and investigative researcher specializing in Geopolitics and Global Macroeconomics using OSINT. Founder of Dashboard Options (Quantitative Finance & AI).","url":"https://x.com/khalidnaami0","imageURL":"/img/khalid_profile.webp","key":"khalid","page":null}],"frontMatter":{"title":"Home Prices Fall: Case-Shiller & FHFA Slump","description":"U.S. home price growth slows as Case-Shiller and FHFA indexes fall. Pandemic-era booms in Texas and Florida reverse under energy shocks and a weak labor market.","authors":["khalid"],"tags":["Global Economy","Real Estate","Debt","Energy Markets","Central Banks","Global Macro"],"keywords":["US Home Prices","Case Shiller Index","FHFA Index","Housing Slump","Florida Housing Market","Texas Real Estate","Economic Slowdown"],"image":"/img/us-housing-market-slowdown.webp","slug":"us-home-prices-decline-case-shiller-fhfa","date":"2026-06-04T14:00:00.000Z","schema_type":["TechArticle","NewsArticle"]},"unlisted":false,"lastUpdatedAt":1783353598000,"lastUpdatedBy":"khalidnaami7","prevItem":{"title":"Private Credit Slump: Swiss Pension Fund Gate","permalink":"/blog/private-credit-slump-swiss-pension-fund-gate"},"nextItem":{"title":"Dashboard Options for Finance: The Quantitative Edge","permalink":"/blog/dashboard-options-finance-quantitative-edge"}}')},94415:(e,t,n)=>{n.r(t),n.d(t,{assets:()=>l,contentTitle:()=>r,default:()=>c,frontMatter:()=>o,metadata:()=>s,toc:()=>h});var s=n(44168),a=n(74848),i=n(28453);const o={title:"Home Prices Fall: Case-Shiller & FHFA Slump",description:"U.S. home price growth slows as Case-Shiller and FHFA indexes fall. Pandemic-era booms in Texas and Florida reverse under energy shocks and a weak labor market.",authors:["khalid"],tags:["Global Economy","Real Estate","Debt","Energy Markets","Central Banks","Global Macro"],keywords:["US Home Prices","Case Shiller Index","FHFA Index","Housing Slump","Florida Housing Market","Texas Real Estate","Economic Slowdown"],image:"/img/us-housing-market-slowdown.webp",slug:"us-home-prices-decline-case-shiller-fhfa",date:new Date("2026-06-04T14:00:00.000Z"),schema_type:["TechArticle","NewsArticle"]},r="Home Prices Fall: Case-Shiller and FHFA Signal Housing Slump",l={authorsImageUrls:[void 0]},h=[{value:"The Pandemic Booms Are Reversing",id:"the-pandemic-booms-are-reversing",level:2},{value:"Case-Shiller Confirms the Turning Point",id:"case-shiller-confirms-the-turning-point",level:2},{value:"Sponsor Spotlight: Monetary Metals",id:"sponsor-spotlight-monetary-metals",level:3},{value:"Inventory Builds While Demand Freezes",id:"inventory-builds-while-demand-freezes",level:2},{value:"FHFA index Signals the Worst Since 2012",id:"fhfa-index-signals-the-worst-since-2012",level:2},{value:"The Illusion of Price Stability",id:"the-illusion-of-price-stability",level:2},{value:"Connecting the Slump to the Stressed Consumer",id:"connecting-the-slump-to-the-stressed-consumer",level:2},{value:"What to Watch From Here",id:"what-to-watch-from-here",level:2}];function d(e){const t={a:"a",blockquote:"blockquote",em:"em",h2:"h2",h3:"h3",hr:"hr",img:"img",li:"li",ol:"ol",p:"p",strong:"strong",ul:"ul",...(0,i.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsxs)(t.p,{children:["Home prices are now doing something they were not supposed to do. After years of being told the housing market was poised to make a comeback on lower interest rates, the data shows something else entirely. First of all, the ",(0,a.jsx)(t.strong,{children:"S&P CoreLogic Case-Shiller"})," index just declined for the second straight month. Not one noisy month, but two in a row."]}),"\n",(0,a.jsx)(t.p,{children:"Plus, that took the year-over-year change to its lowest level in several years. But even going farther than that, the government's own price data didn't just confirm S&P Case-Shiller. What it showed was the lowest year-over-year change in 14 years, going all the way back to the bottom of the last big housing bust."}),"\n",(0,a.jsx)(t.p,{children:"Different methodology, different sample, different construction, same conclusion. Home price growth is slowing and slowing fast, and in more markets, home prices are not just slowing, they're actually in real trouble. And the weakness is being led by exactly the places you'd expect at this stage of the cycle: Texas and Florida."}),"\n",(0,a.jsx)(t.p,{children:(0,a.jsx)(t.img,{alt:"U.S. Housing Market Slowdown",src:n(17747).A+"",width:"600",height:"337"})}),"\n",(0,a.jsx)(t.hr,{}),"\n",(0,a.jsx)(t.h2,{id:"the-pandemic-booms-are-reversing",children:"The Pandemic Booms Are Reversing"}),"\n",(0,a.jsx)(t.p,{children:'These were among the hottest pandemic-era housing markets. They had the migration boom, the investment boom, the construction boom, the short-term rental boom\u2014the "everybody is moving here" boom. We are talking about Austin, Dallas, San Antonio, Tampa, Orlando, Jacksonville, Cape Coral, North Port, and parts of South Florida. These markets were treated as if demand was limitless.'}),"\n",(0,a.jsx)(t.p,{children:"And it might have been had the economy actually been strong and resilient. Now builders are discounting, sellers are cutting prices, and insurance costs are crushing affordability, particularly in Florida. Property taxes and carrying costs are biting in Texas along with that former price appreciation. Investors are stepping away, and any buyers who are left are facing a deteriorating labor situation: jobs, incomes, crushing insurance costs, and affordability issues that are all wrapped up into the same labor market dynamic, plus falling consumer confidence."}),"\n",(0,a.jsx)(t.p,{children:"We got more evidence of that earlier today as well. Consumer confidence is down, jobs, incomes, and the housing market. It's not really about interest rates. It's about a whole lot more than that. And that was before we even got to the energy shock. That's the biggest thing about housing right now. It tells us in no uncertain terms that consumers are not just being pessimistic for the sake of pessimism. They are acting on those impulses and acting in bigger and bigger ways."}),"\n",(0,a.jsx)(t.hr,{}),"\n",(0,a.jsx)(t.h2,{id:"case-shiller-confirms-the-turning-point",children:"Case-Shiller Confirms the Turning Point"}),"\n",(0,a.jsxs)(t.p,{children:["Let's start with Case-Shiller. The ",(0,a.jsx)(t.a,{href:"https://en.wikipedia.org/wiki/Case%E2%80%93Shiller_index",children:"S&P CoreLogic Case-Shiller Index"})," is one of the most widely followed home price measures in the country because it looks at repeat sales. In other words, it's not just comparing whatever mix of homes happen to sell this month versus last month. It's trying to track price changes for the same homes over time. And that makes it useful for spotting turning points."]}),"\n",(0,a.jsx)(t.p,{children:"And the latest turning point is pretty obvious. The 20-city index has now declined for two consecutive months on a seasonally adjusted basis. The national average was basically zero in February before also falling in March, which is the latest data that just came out."}),"\n",(0,a.jsx)(t.p,{children:(0,a.jsx)(t.img,{alt:"U.S. Case-Shiller and FHFA Home Price Trends",src:n(1694).A+"",width:"600",height:"337"})}),"\n",(0,a.jsx)(t.p,{children:"And that matters because housing usually has a seasonal pattern. Prices tend to firm up in the spring and summer when activity is stronger and then soften later in the year. So, when prices are falling even after seasonal adjustments, it means the weakness is not just normal calendar noise. It means the market is softening underneath the surface. And the year-over-year rate is even more important. Case-Shiller's annual growth rate slowed to the weakest reading in several years going back to 2023. And this time it's not about rising interest rates."}),"\n",(0,a.jsx)(t.p,{children:"Now, that does not mean every city is down year-over-year. It doesn't mean every homeowner is underwater. It means the rate of appreciation that defined the post-pandemic housing bubble is gone. That's a major macro change."}),"\n",(0,a.jsx)(t.hr,{}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsx)(t.h3,{id:"sponsor-spotlight-monetary-metals",children:"Sponsor Spotlight: Monetary Metals"}),"\n",(0,a.jsxs)(t.p,{children:["What if your gold could actually pay you every single month in more gold? That's what today's sponsor, ",(0,a.jsx)(t.a,{href:"https://monetary-metals.com",children:"Monetary Metals"}),", lets you do."]}),"\n",(0,a.jsx)(t.p,{children:"Here's how it works: You still own the gold, it's still in your name, it's fully insured, but instead of just sitting there doing nothing, it actually starts working for you. Monetary Metals has built a system that turns idle gold into productive gold, earning real yield paid in physical gold, not dollars. No selling, no trading, no converting. You keep your gold and every month you get more of it."}),"\n",(0,a.jsxs)(t.p,{children:["If you're a long-term gold holder looking for a smarter way to store value, check them out at ",(0,a.jsx)(t.a,{href:"https://monetary-metals.com",children:"monetary-metals.com"})," to see if they're the right fit for you."]}),"\n"]}),"\n",(0,a.jsx)(t.hr,{}),"\n",(0,a.jsx)(t.h2,{id:"inventory-builds-while-demand-freezes",children:"Inventory Builds While Demand Freezes"}),"\n",(0,a.jsx)(t.p,{children:"For a long time, the housing market had two conflicting forces. On the one side, affordability was historically bad. Mortgage payments were too high, prices got to be too high, and insurance, taxes, and maintenance were way too high. Buyers just got to be exhausted."}),"\n",(0,a.jsx)(t.p,{children:"But on the other side, inventory was extremely low. Homeowners with 3% mortgages refused to sell. That kept supply tight, and tight supply kept prices from falling as much as affordability suggested that they should."}),"\n",(0,a.jsxs)(t.p,{children:["Now, existing homeowners who waited for the spring rebound this year are finding out that the buyer pool is not what it used to be. That's how you get two monthly declines in a row for Case-Shiller. This transition is highly reminiscent of the trend we explored in our analysis of ",(0,a.jsx)(t.a,{href:"/blog/home-sales-plunging-2010-levels",children:"home sales plunging to 2010 levels"}),", where a hidden labor market contraction began to freeze buyer demand."]}),"\n",(0,a.jsx)(t.p,{children:"The important point is not that the national index is suddenly collapsing, because it's not. The important point is that the direction has changed, and the annual growth rate is now at a multi-year low."}),"\n",(0,a.jsxs)(t.p,{children:["Housing is a slow-moving market. It usually doesn't fall apart all at once. First, you see sales that freeze up and inventory begins to build. Then sellers resist reality, but eventually they have to cut prices, and then indexes begin to slow. Next, the weakest local markets go negative, and eventually the national numbers follow. We are well into that sequence now, showing a trend where ",(0,a.jsx)(t.a,{href:"/blog/new-home-sales-collapse-energy-shock",children:"new home sales collapse under energy shocks"})," before index prices even reflect the full extent of the macroeconomic damage."]}),"\n",(0,a.jsx)(t.hr,{}),"\n",(0,a.jsx)(t.h2,{id:"fhfa-index-signals-the-worst-since-2012",children:"FHFA index Signals the Worst Since 2012"}),"\n",(0,a.jsxs)(t.p,{children:["The ",(0,a.jsx)(t.a,{href:"https://www.fhfa.gov/data/hpi",children:"FHFA House Price Index"})," is telling us the same exact story from a slightly, if not materially, different angle. It's constructed differently than Case-Shiller, which is a positive here. FHFA is based on mortgages backed by Fannie and Freddie, so it doesn't capture the entire housing market in the same way. It excludes some jumbo loans and cash transactions, giving it a different geographic and price tier mix."]}),"\n",(0,a.jsx)(t.p,{children:"But that's exactly what makes it so useful. When Case-Shiller and FHFA are both saying home price growth has slowed to multi-year lows, you can't dismiss it as a quirk of one index or another. You can't say it's just luxury markets or just cash buyers or one metropolitan area or just one methodology. Both indexes are pointing in the same direction."}),"\n",(0,a.jsxs)(t.p,{children:["FHFA shows home price appreciation really losing steam. The monthly numbers have weakened and the year-over-year rate has just flopped, coming in at ",(0,a.jsx)(t.strong,{children:"1.71%"})," for the month of March. It doesn't sound bad, but in fact it's the worst for the index since March of 2012\u2014back when the country was just starting to crawl out of the worst housing crisis."]}),"\n",(0,a.jsx)(t.p,{children:"Again, this is not the same as saying every market is crashing in 2026. The Northeast and parts of the Midwest remain relatively stable because those regions didn't quite overbuild to the same degree and inventory in many of those places is still somewhat tight. But the national average is being pulled lower by the markets where the pandemic boom went the farthest, and that means Texas and Florida."}),"\n",(0,a.jsx)(t.p,{children:"This is exactly how housing cycles work. The most speculative markets lead on the way up, and they also lead on the way down. The buyer who moved from California or New York in 2021 is not the marginal buyer any longer. The marginal buyer in 2026 is a household looking at a mortgage rate that's still too high for them, a home price that's still way too high, an insurance quote that may be shocking, and a labor market that no longer feels secure. That buyer is no longer chasing houses; they are waiting."}),"\n",(0,a.jsx)(t.hr,{}),"\n",(0,a.jsx)(t.h2,{id:"the-illusion-of-price-stability",children:"The Illusion of Price Stability"}),"\n",(0,a.jsx)(t.p,{children:"The housing market is not healed because home prices have stopped growing. After prices soared ahead by 50% during the bubble period, coming in flat doesn't magically fix affordability. Even if it was down a couple percentage points, that doesn't solve the core issue."}),"\n",(0,a.jsx)(t.p,{children:"When you hear that home price growth has slowed to a multi-year low, don't confuse that with relief. For buyers, the problem is still affordability, which means incomes. Ownership costs outpaced wages, pricing more and more Americans right out of the marketplace. Many possible home buyers who might have been on the fence were shoved right back on the wrong side of it."}),"\n",(0,a.jsx)(t.p,{children:"For sellers, the problem is expectations. They still remember '21 and '22. They remember bidding wars, waived inspections, and homes selling in a weekend. But that market is gone. Now, buyers are asking for concessions, comparing listings, waiting for price cuts, and choosing new construction if the builder gives them a better deal. They're doing what buyers normally do when they regain leverage."}),"\n",(0,a.jsx)(t.p,{children:"And that transition is painful because housing is emotional. Sellers don't cut prices quickly. They resist, de-list, wait, and blame the season, the Fed, or the media. But eventually, if they need to sell, price becomes the adjustment mechanism. And that's what the indexes are beginning to show."}),"\n",(0,a.jsx)(t.hr,{}),"\n",(0,a.jsx)(t.h2,{id:"connecting-the-slump-to-the-stressed-consumer",children:"Connecting the Slump to the Stressed Consumer"}),"\n",(0,a.jsx)(t.p,{children:"The Conference Board's May 2026 report on consumer confidence showed yet again that consumer confidence slipped on the same concerns that have been building. The energy shock, in many ways, just amplified everyone's fears. Consumers are plainly worried about growth and what happens when it costs more to fill up at the pump. That means households are getting squeezed from both sides. On the one, they're less confident about the economy, jobs, and future income. On the other, they're still dealing with high prices for gasoline."}),"\n",(0,a.jsx)(t.p,{children:"And that's exactly the environment where big-ticket spending gets delayed. Buying a house is the ultimate big-ticket decision. It requires confidence, job security, savings, and access to credit. It requires belief that the future will be stable enough to take on a 30-year obligation."}),"\n",(0,a.jsx)(t.p,{children:"If households expect business conditions or job availability to weaken even further, they're going to be even less likely to make major financial commitments. That shows up first in discretionary categories: fewer restaurant visits, fewer vacations, fewer home improvement projects, and deferred appliance purchases. Then it shows up in housing. If consumers are cutting back nights out because of gasoline, they sure as hell aren't going to be signing up for a new house and a new mortgage."}),"\n",(0,a.jsx)(t.p,{children:"Gasoline has a unique psychological effect. People see the price constantly. They pass it on the road and feel it every time they go to the station. When gas moves higher, lower-middle-income households have to adjust immediately. This is happening after several years of cumulative problems: higher grocery bills, rent, insurance, and car payments. wages are not enough to keep up with past price changes."}),"\n",(0,a.jsx)(t.p,{children:"This is why Walmart can be strong while the consumer is weak\u2014higher-income households trading down to Walmart is a sign of value-seeking behavior. It's why Kroger is talking about price investments to cut costs for customers. It's why Lowe's called the housing market the most difficult since the financial crisis. Home improvement is about confidence, and people delay when they don't feel secure about their income or equity."}),"\n",(0,a.jsx)(t.p,{children:"When home prices slow or fall, the wealth effect reverses. Homeowners become more cautious, builders discount, and furniture and appliance stores weaken. That's the housing feedback loop, and it is already visible:"}),"\n",(0,a.jsxs)(t.ul,{children:["\n",(0,a.jsxs)(t.li,{children:[(0,a.jsx)(t.strong,{children:"Depressed Sales"}),": Existing home sales have been stuck at heavily depressed levels."]}),"\n",(0,a.jsxs)(t.li,{children:[(0,a.jsx)(t.strong,{children:"Weak Applications"}),": Mortgage purchase applications remain extremely weak."]}),"\n",(0,a.jsxs)(t.li,{children:[(0,a.jsx)(t.strong,{children:"Rising Stress"}),": Delinquencies are no longer falling, and foreclosures are rising."]}),"\n"]}),"\n",(0,a.jsx)(t.hr,{}),"\n",(0,a.jsx)(t.h2,{id:"what-to-watch-from-here",children:"What to Watch From Here"}),"\n",(0,a.jsx)(t.p,{children:"Moving forward, there are three critical factors to watch:"}),"\n",(0,a.jsxs)(t.ol,{children:["\n",(0,a.jsxs)(t.li,{children:[(0,a.jsx)(t.strong,{children:"Inventory Levels"}),": If active listings keep rising in Texas and Florida, prices will stay under pressure."]}),"\n",(0,a.jsxs)(t.li,{children:[(0,a.jsx)(t.strong,{children:"Builder Incentives"}),": If buy-downs and discounts get bigger, it tells you the market is weaker than the headline prices suggest."]}),"\n",(0,a.jsxs)(t.li,{children:[(0,a.jsx)(t.strong,{children:"Insurance and Taxes"}),": In states like Florida, the all-in monthly payment matters far more than the listing price."]}),"\n"]}),"\n",(0,a.jsx)(t.p,{children:"The housing market is not saying everything's going to crash tomorrow, but it is absolutely sending a macroeconomic slowdown signal. The pandemic-era boom is over, and the market right now is sending us a very clear warning about the real state of the global economy."}),"\n",(0,a.jsx)(t.hr,{}),"\n",(0,a.jsx)(t.p,{children:(0,a.jsxs)(t.em,{children:["Monitor global macroeconomic indicators, options volume, and liquidity regimes in real-time with ",(0,a.jsx)(t.a,{href:"https://dashboardoptions.com/",children:"Dashboard Options"}),"."]})})]})}function c(e={}){const{wrapper:t}={...(0,i.R)(),...e.components};return t?(0,a.jsx)(t,{...e,children:(0,a.jsx)(d,{...e})}):d(e)}}}]);